// Google.Units · pack:google
const __vr_google_units_nbsp = (() => {
const v16_units_rule = {
  id: 'google-units-nbsp',
  family: FAM.C,
  defaultSeverity: 'advisory',
  pack: 'google',
  run(ctx, emit) {
    // A number immediately joined to a data-size or time unit (no space).
    // Trailing (?![A-Za-z]) stops the unit being part of a longer word. Ambiguous
    // single-letter units (d/s/h/B) are excluded: "the 60s", "3d rendering", "747s".
    const re = /\b(\d+)(kB|MB|GB|TB|min|ns|ms)(?![A-Za-z])/g;
    scan(ctx, re, (m, i) => {
      if (ctx.isTableLine(i)) return;
      emitAt(ctx, emit, 'google-units-nbsp', FAM.C, 'advisory', i, m[0].length,
        `Put a nonbreaking space between the number and the unit in "${m[0]}".`);
    });
  }
};
return v16_units_rule;
})();

// Google.We · pack:google
const __vr_avoid_first_person_plural = (() => {
const v17_we_rule = {
  id: 'avoid-first-person-plural', family: FAM.C, defaultSeverity: 'advisory', pack: 'google',
  run(ctx, emit) {
    const hits = [];
    scan(ctx, /\b(we|we'(?:ve|re)|ours?|us|let's)\b/gi, (m, i) => hits.push({ m, i }));
    if (hits.length < 2) return; // common words; require >=2 so a single legit use doesn't fire
    for (const h of hits) emitAt(ctx, emit, this.id, this.family, 'advisory', h.i, h.m[0].length, `Google style: avoid first-person plural "${h.m[0]}" — address the reader directly.`);
  },
};
return v17_we_rule;
})();

// Google.Will · pack:google
